import{_ as a,o as d,c as l,a2 as i}from"./chunks/framework.DnrXFDHb.js";const u=JSON.parse('{"title":"800kV HVDC 输电——中国标准走向全球","description":"","frontmatter":{"updated":"2026-06-23T00:00:00.000Z","visibility":"public"},"headers":[],"relativePath":"电力新能源/新赛道/_深化_2026-06-16_800V高压直流输电与设备国产化.md","filePath":"电力新能源/新赛道/_深化_2026-06-16_800V高压直流输电与设备国产化.md","lastUpdated":1782226922000}'),r={name:"电力新能源/新赛道/_深化_2026-06-16_800V高压直流输电与设备国产化.md"};function e(o,t,h,n,s,c){return d(),l("div",null,[...t[0]||(t[0]=[i(`<h1 id="_800kv-hvdc-输电——中国标准走向全球" tabindex="-1">800kV HVDC 输电——中国标准走向全球 <a class="header-anchor" href="#_800kv-hvdc-输电——中国标准走向全球" aria-label="Permalink to &quot;800kV HVDC 输电——中国标准走向全球&quot;">​</a></h1><h2 id="摘要" tabindex="-1">摘要 <a class="header-anchor" href="#摘要" aria-label="Permalink to &quot;摘要&quot;">​</a></h2><p>800kV 特高压直流输电（UHVDC）是中国在电力装备领域实现全球引领的标志性技术。ABB、HITACHI 退出后，中国已实现全产业链 100% 国产化。2026 年国内直流特高压在建项目 10 条（5 直 5 交），2025-2028 年 CAGR 28%-40%。柔直（VSC-HVDC）技术正在崛起，对应新增 ±800kV/±500kV 柔直海陆市场。核心设备（换流阀/换流变/直流穿墙套管/直流断路器）已完全国产化，国产替代率从 3% 升至 80%+。</p><h2 id="全球格局变化" tabindex="-1">全球格局变化 <a class="header-anchor" href="#全球格局变化" aria-label="Permalink to &quot;全球格局变化&quot;">​</a></h2><h3 id="abb-hitachi-退出后" tabindex="-1">ABB/HITACHI 退出后 <a class="header-anchor" href="#abb-hitachi-退出后" aria-label="Permalink to &quot;ABB/HITACHI 退出后&quot;">​</a></h3><ul><li>中国掌握 ±800kV/±1100kV 全系列技术，独步全球</li><li>全球直流输电市场格局：<strong>中方独大，无国际对手</strong></li><li>中国标准成为事实上的全球直流输电标准</li><li>&quot;一带一路&quot;出口潜力巨大</li></ul><h3 id="全产业链国产化" tabindex="-1">全产业链国产化 <a class="header-anchor" href="#全产业链国产化" aria-label="Permalink to &quot;全产业链国产化&quot;">​</a></h3><table tabindex="0"><thead><tr><th>设备</th><th>国产化率</th><th>2020 年前</th><th>2026 年</th></tr></thead><tbody><tr><td>换流阀</td><td>100%</td><td>进口为主</td><td>完全国产，代表企业：许继电气/中国西电/四方股份</td></tr><tr><td>换流变压器</td><td>100%</td><td>进口为主</td><td>完全国产</td></tr><tr><td>直流穿墙套管</td><td>100%</td><td>国产 3%-5%</td><td>完全国产（中国西电/特变电工）</td></tr><tr><td>直流断路器</td><td>100%</td><td>进口为主</td><td>国产主导（平高电气/中国西电）</td></tr><tr><td>控制保护系统</td><td>100%</td><td>进口为主</td><td>国产（南瑞继保/许继电气）</td></tr><tr><td>DC/DC 变换器</td><td>国产突破</td><td>N/A</td><td>2026 年首条直流汇流示范工程将投用</td></tr><tr><td>大容量直流变压器</td><td>国产突破</td><td>N/A</td><td>首个应用示范工程已启动</td></tr><tr><td>IGBT 功率模块</td><td>80%+</td><td>进口</td><td>中车时代/士兰微/比亚迪半导体</td></tr><tr><td>传感器/PMU</td><td>100%</td><td>国际品牌 70%</td><td>国产替代（四方股份）</td></tr><tr><td>高压电缆绝缘料</td><td>100%</td><td>进口 90%</td><td>万马高分子/青岛汉缆</td></tr></tbody></table><h2 id="国内建设规划" tabindex="-1">国内建设规划 <a class="header-anchor" href="#国内建设规划" aria-label="Permalink to &quot;国内建设规划&quot;">​</a></h2><h3 id="_2026-年在建特高压项目" tabindex="-1">2026 年在建特高压项目 <a class="header-anchor" href="#_2026-年在建特高压项目" aria-label="Permalink to &quot;2026 年在建特高压项目&quot;">​</a></h3><p><strong>直流（5 条）</strong>：</p><ol><li>陇东-山东 ±800kV（甘肃→山东，新能源外送）</li><li>哈密-重庆 ±800kV（新疆→重庆）</li><li>金上-湖北 ±800kV（西藏/四川→湖北）</li><li>宁夏-湖南 ±800kV（宁夏→湖南）</li><li>巴林-奈曼-阜新 ±800kV（蒙东→辽宁）</li></ol><p><strong>交流（5 条）</strong>：</p><ol><li>川渝特高压交流</li><li>张北-胜利交流</li><li>潘多-唐山交流</li><li>大同-怀来-天津交流</li><li>攀西-川南交流</li></ol><h3 id="设备企业受益顺序" tabindex="-1">设备企业受益顺序 <a class="header-anchor" href="#设备企业受益顺序" aria-label="Permalink to &quot;设备企业受益顺序&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>换流阀/保护设备（设备进入早，确认收入快）</span></span>
<span class="line"><span>  → 换流变/穿墙套管（单价最高，弹性大）</span></span>
<span class="line"><span>    → IGBT 功率模块（远期替代，弹性高）</span></span></code></pre></div><h2 id="柔直-vsc-hvdc-崛起" tabindex="-1">柔直（VSC-HVDC）崛起 <a class="header-anchor" href="#柔直-vsc-hvdc-崛起" aria-label="Permalink to &quot;柔直（VSC-HVDC）崛起&quot;">​</a></h2><h3 id="与传统-lcc-hvdc-对比" tabindex="-1">与传统 LCC-HVDC 对比 <a class="header-anchor" href="#与传统-lcc-hvdc-对比" aria-label="Permalink to &quot;与传统 LCC-HVDC 对比&quot;">​</a></h3><table tabindex="0"><thead><tr><th>维度</th><th>LCC-HVDC（传统）</th><th>VSC-HVDC（柔直）</th></tr></thead><tbody><tr><td>适用场景</td><td>点对点大容量输电</td><td>多端直流、海上风电并网、城市配网</td></tr><tr><td>逆变更复杂</td><td>有换相失败风险</td><td>无换相失败，可自换相</td></tr><tr><td>容量</td><td>超大规模（GW 级）</td><td>几百 MW~GW 级</td></tr><tr><td>成本</td><td>较低</td><td>较高（但差距在缩小）</td></tr><tr><td>市场增速</td><td>稳定</td><td>快（海上风电驱动）</td></tr></tbody></table><h3 id="柔直市场" tabindex="-1">柔直市场 <a class="header-anchor" href="#柔直市场" aria-label="Permalink to &quot;柔直市场&quot;">​</a></h3><ul><li>对应新增 ±800kV/±500kV 柔直海陆市场</li><li>2025 年国内特高压招标金额约 1178 亿元 + 柔直约 300-400 亿元</li><li>海上风电远距离送出是柔直最主要增量市场</li><li>柔直技术难度更高，设备毛利率更高</li></ul><h2 id="出口潜力" tabindex="-1">出口潜力 <a class="header-anchor" href="#出口潜力" aria-label="Permalink to &quot;出口潜力&quot;">​</a></h2><ul><li><strong>巴西美丽山</strong>：国家电网 ±800kV 直流项目（南美首条），已稳定运行，成为&quot;中国出口名片&quot;</li><li><strong>东南亚</strong>：印尼/老挝/缅甸水电送出</li><li><strong>中亚</strong>：可再生能源外送需求</li><li><strong>非洲</strong>：刚果/赞比亚水电送出</li><li><strong>中东/北非</strong>：沙漠风电/光伏外送</li></ul><h2 id="投资逻辑" tabindex="-1">投资逻辑 <a class="header-anchor" href="#投资逻辑" aria-label="Permalink to &quot;投资逻辑&quot;">​</a></h2><ol><li><strong>确定性增长</strong>：2025-2028 年特高压建设 CAGR 28%-40%</li><li><strong>国产替代深化</strong>：核心设备 100% 国产化，不受制于人</li><li><strong>柔直弹性</strong>：毛利率更高，增量市场大</li><li><strong>出口潜力</strong>：中国标准全球输出</li></ol><h2 id="风险提示" tabindex="-1">风险提示 <a class="header-anchor" href="#风险提示" aria-label="Permalink to &quot;风险提示&quot;">​</a></h2><ol><li>特高压投资高度依赖电网规划，节奏可能放缓</li><li>柔直技术仍在演进，标准尚未完全统一</li><li>部分核心 IGBT 仍依赖进口替代</li><li>海外出口受地缘政治影响</li><li>设备毛利率趋降（竞争加剧）</li></ol><hr><p><em>来源：国家电网、经济观察网、中信建投研报、券商研报</em><em>更新：2026-06-16</em></p>`,29)])])}const b=a(r,[["render",e]]);export{u as __pageData,b as default};
